-- Faza 1 modyfikacji przed instalatorem: fabryczny katalog dokładnie 350 instrumentów
-- zamiast prowizorycznej listy 11 z Celu 1.4, z pełnym, wersjonowanym zestawem parametrów
-- obliczeniowych. Dane wygenerowane programowo skryptem generate_instrument_catalog.js ze
-- źródła `Prompt_modyfikacja_Dziennika_Tradera.docx` (nigdy nie przepisywane ręcznie).

-- Przepisany silnik obliczeń rozróżnia walutę wyniku instrumentu i walutę rachunku - jeżeli
-- się różnią, transakcja przechowuje świadomie wpisany/edytowalny kurs przeliczeniowy zamiast
-- cichego przybliżenia (sekcja "Obliczenia TP, SL i wyniku").
ALTER TABLE trades ADD COLUMN conversion_rate TEXT;

CREATE TABLE instrument_versions (
    id TEXT PRIMARY KEY,
    instrument_id TEXT NOT NULL REFERENCES instruments (id),
    version_number INTEGER NOT NULL,
    is_active INTEGER NOT NULL DEFAULT 1,
    currency_base TEXT NOT NULL,
    currency_profit TEXT NOT NULL,
    currency_margin TEXT NOT NULL,
    digits INTEGER NOT NULL,
    point TEXT NOT NULL,
    trade_tick_size TEXT NOT NULL,
    trade_tick_value TEXT NOT NULL,
    tick_value_profit TEXT NOT NULL,
    tick_value_loss TEXT NOT NULL,
    contract_size TEXT NOT NULL,
    volume_min TEXT NOT NULL,
    volume_max TEXT NOT NULL,
    volume_step TEXT NOT NULL,
    volume_limit TEXT NOT NULL,
    calc_mode TEXT NOT NULL,
    trade_mode TEXT NOT NULL,
    execution_mode TEXT NOT NULL,
    order_mode_flags INTEGER NOT NULL,
    filling_mode_flags INTEGER NOT NULL,
    expiration_mode_flags INTEGER NOT NULL,
    spread_floating INTEGER NOT NULL,
    stops_level_points INTEGER NOT NULL,
    freeze_level_points INTEGER NOT NULL,
    margin_initial TEXT NOT NULL,
    margin_maintenance TEXT NOT NULL,
    margin_hedged TEXT NOT NULL,
    margin_hedged_use_leg INTEGER NOT NULL,
    liquidity_rate TEXT NOT NULL,
    margin_rate_buy_initial TEXT NOT NULL,
    margin_rate_buy_maintenance TEXT NOT NULL,
    margin_rate_sell_initial TEXT NOT NULL,
    margin_rate_sell_maintenance TEXT NOT NULL,
    swap_mode TEXT NOT NULL,
    swap_long TEXT NOT NULL,
    swap_short TEXT NOT NULL,
    swap_sunday TEXT NOT NULL,
    swap_monday TEXT NOT NULL,
    swap_tuesday TEXT NOT NULL,
    swap_wednesday TEXT NOT NULL,
    swap_thursday TEXT NOT NULL,
    swap_friday TEXT NOT NULL,
    swap_saturday TEXT NOT NULL,
    triple_swap_day TEXT NOT NULL,
    quote_sessions TEXT NOT NULL,
    trade_sessions TEXT NOT NULL,
    start_time TEXT,
    expiration_time TEXT,
    created_at TEXT NOT NULL
);

CREATE INDEX idx_instrument_versions_instrument_id ON instrument_versions (instrument_id);
CREATE UNIQUE INDEX idx_instrument_versions_active ON instrument_versions (instrument_id) WHERE is_active = 1;

CREATE TABLE instrument_preferences (
    instrument_id TEXT PRIMARY KEY REFERENCES instruments (id),
    is_visible INTEGER NOT NULL DEFAULT 0,
    sort_order INTEGER NOT NULL DEFAULT 0,
    is_favorite INTEGER NOT NULL DEFAULT 0
);

-- Ten katalog 350 instrumentów zastępuje prowizoryczną fabryczną listę 11 pozycji z Celu 1.4.
-- Usuń stare fabryczne wiersze, ale TYLKO te, do których nie odwołuje się żadna transakcja -
-- to nie jest utrata danych użytkownika, to wymiana samego fabrycznego punktu startowego.
DELETE FROM instruments
WHERE id IN ('01978e6b-0001-7000-8000-000000000001', '01978e6b-0001-7000-8000-000000000002', '01978e6b-0001-7000-8000-000000000003', '01978e6b-0001-7000-8000-000000000004', '01978e6b-0001-7000-8000-000000000005', '01978e6b-0001-7000-8000-000000000006', '01978e6b-0001-7000-8000-000000000007', '01978e6b-0001-7000-8000-000000000008', '01978e6b-0001-7000-8000-000000000009', '01978e6b-0001-7000-8000-000000000010', '01978e6b-0001-7000-8000-000000000011')
  AND id NOT IN (SELECT DISTINCT instrument_id FROM trades WHERE instrument_id IS NOT NULL);

-- Przebuduj `instruments` do nowego kształtu tożsamości W MIEJSCU (ALTER TABLE, nigdy DROP +
-- odtworzenie) - `trades`, i zaraz też `instrument_versions`/`instrument_preferences`, mają
-- klucze obce do tej tabeli; z włączonymi kluczami obcymi `DROP TABLE` wykonuje niejawne
-- `DELETE FROM` sprawdzane tak, jakby ktoś naprawdę usuwał te wiersze, więc wywaliłoby się na
-- każdym ocalałym odwołaniu. Dodanie/usunięcie kolumn zachowuje tożsamość wierszy (te same id),
-- więc żadne istniejące odwołanie nigdy nie traci celu.
ALTER TABLE instruments ADD COLUMN display_symbol TEXT;
ALTER TABLE instruments ADD COLUMN source_symbol TEXT;
ALTER TABLE instruments ADD COLUMN factory_index INTEGER;

-- Wypełnij nowe kolumny dla wierszy, które przetrwały powyższe czyszczenie. Jeżeli nazwa
-- koliduje z nowym katalogiem fabrycznym wstawianym niżej, odróżnij dopiskiem zamiast cichej
