-- Zachowaj wersję parametrów każdego ocalałego starego instrumentu w nowym, wersjonowanym
-- kształcie, zanim usuniemy stare kolumny liczbowe z `instruments`.
INSERT INTO instrument_versions (
    id, instrument_id, version_number, is_active,
    currency_base, currency_profit, currency_margin,
    digits, point, trade_tick_size, trade_tick_value, tick_value_profit, tick_value_loss, contract_size,
    volume_min, volume_max, volume_step, volume_limit,
    calc_mode, trade_mode, execution_mode,
    order_mode_flags, filling_mode_flags, expiration_mode_flags,
    spread_floating, stops_level_points, freeze_level_points,
    margin_initial, margin_maintenance, margin_hedged, margin_hedged_use_leg,
    liquidity_rate, margin_rate_buy_initial, margin_rate_buy_maintenance,
    margin_rate_sell_initial, margin_rate_sell_maintenance,
    swap_mode, swap_long, swap_short,
    swap_sunday, swap_monday, swap_tuesday, swap_wednesday, swap_thursday, swap_friday, swap_saturday,
    triple_swap_day, quote_sessions, trade_sessions, start_time, expiration_time, created_at
)
SELECT
    lower(hex(randomblob(4))) || '-' || lower(hex(randomblob(2))) || '-7' || substr(lower(hex(randomblob(2))), 2) || '-8' || substr(lower(hex(randomblob(2))), 2) || '-' || lower(hex(randomblob(6))),
    id, 1, 1,
    quote_currency, settlement_currency, settlement_currency,
    decimal_places, tick_size, tick_size, tick_value_per_lot, tick_value_per_lot, tick_value_per_lot, contract_size,
    min_lot, '100000.000000000000', lot_step, '0.000000000000',
    'SYMBOL_CALC_MODE_CFD', 'SYMBOL_TRADE_MODE_FULL', 'SYMBOL_TRADE_EXECUTION_MARKET',
    63, 1, 15,
    1, 0, 0,
    '0.000000000000', '0.000000000000', '0.000000000000', 0,
    '0.000000000000', '1.000000000000', '1.000000000000', '1.000000000000', '1.000000000000',
    'SYMBOL_SWAP_MODE_POINTS', '0.000000000000', '0.000000000000',
    '1.000000000000', '1.000000000000', '1.000000000000', '1.000000000000', '1.000000000000', '1.000000000000', '1.000000000000',
    'ENUM_DAY_OF_WEEK::7', '', '', NULL, NULL, created_at
FROM instruments
WHERE factory_index IS NULL;

INSERT INTO instrument_preferences (instrument_id, is_visible, sort_order, is_favorite)
SELECT id, 1, 9000 + rowid, 0 FROM instruments WHERE factory_index IS NULL;

-- Usuń stary indeks na `symbol` z Celu 1.2, inaczej DROP COLUMN nie pozwoli usunąć kolumny,
-- do której ten indeks się odwołuje.
DROP INDEX idx_instruments_symbol;

-- Usuń stare kolumny liczbowe (przeniesione wyżej do `instrument_versions`) i ujednolic
-- nazewnictwo pozostałych - `name` opisywało instrument, teraz to `description`.
ALTER TABLE instruments DROP COLUMN symbol;
ALTER TABLE instruments DROP COLUMN decimal_places;
ALTER TABLE instruments DROP COLUMN tick_size;
ALTER TABLE instruments DROP COLUMN tick_value_per_lot;
ALTER TABLE instruments DROP COLUMN contract_size;
ALTER TABLE instruments DROP COLUMN pip_size;
ALTER TABLE instruments DROP COLUMN quote_currency;
ALTER TABLE instruments DROP COLUMN settlement_currency;
ALTER TABLE instruments DROP COLUMN min_lot;
ALTER TABLE instruments DROP COLUMN lot_step;
ALTER TABLE instruments DROP COLUMN is_active;
ALTER TABLE instruments RENAME COLUMN name TO description;

CREATE UNIQUE INDEX idx_instruments_display_symbol ON instruments (display_symbol);
CREATE UNIQUE INDEX idx_instruments_source_symbol ON instruments (source_symbol);
CREATE INDEX idx_instruments_category ON instruments (category);

